import{_ as a,c as t,o as i,aN as e}from"./chunks/framework.CqA5BTDU.js";const k=JSON.parse('{"title":"文件传输","description":"","frontmatter":{},"headers":[],"relativePath":"03.远程运维/04-文件传输.md","filePath":"03.远程运维/04-文件传输.md","lastUpdated":null}'),p={name:"03.远程运维/04-文件传输.md"};function d(n,s,h,l,o,c){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="文件传输" tabindex="-1">文件传输 <a class="header-anchor" href="#文件传输" aria-label="Permalink to &quot;文件传输&quot;">​</a></h1><p>远程传输文件在运维里几乎每天都会遇到——上传配置文件、下载日志、同步发布包、备份拉取。场景不同，工具选择也不同。这篇文章梳理 <code>scp</code>、<code>sftp</code>、<code>rsync</code>、<code>lrzsz</code> 各自的适用场景和容易踩的坑。</p><h2 id="一、三个工具-各管一摊" tabindex="-1">一、三个工具，各管一摊 <a class="header-anchor" href="#一、三个工具-各管一摊" aria-label="Permalink to &quot;一、三个工具，各管一摊&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>擅长什么</th><th>为什么不适合别的事</th></tr></thead><tbody><tr><td><code>scp</code></td><td>临时传一两个文件</td><td>不支持增量，重复传很多不变文件也全量</td></tr><tr><td><code>sftp</code></td><td>交互式登录后浏览和取文件</td><td>交互式，不好写脚本自动化</td></tr><tr><td><code>rsync</code></td><td>增量同步、保留属性、断点续传</td><td>只传一个几 KB 小文件没必要用它</td></tr><tr><td><code>lrzsz</code></td><td>终端里临时拖一个小文件</td><td>依赖终端客户端支持 ZMODEM，生产批量传输不适合</td></tr></tbody></table><p>选择的关键区别在于：<code>scp</code> 和 <code>sftp</code> 每次都是全量传完，<code>rsync</code> 会两边比对后只传差异。所以 <code>scp</code> 第一次传和第五次传代价一样，<code>rsync</code> 第二次以后的传输量可以小很多。</p><p>远程路径的写法：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user@host:/path/to/file</span></span></code></pre></div><p>本地传到远端：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>本地路径 -&gt; user@host:远端路径</span></span></code></pre></div><p>远端下载到本地：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user@host:远端路径 -&gt; 本地路径</span></span></code></pre></div><p>传文件之前确认三件事可以避免一半以上的低级错误：</p><table tabindex="0"><thead><tr><th>检查项</th><th>如果不检查</th></tr></thead><tbody><tr><td>目标目录是否存在</td><td>想传到 <code>/etc/nginx/conf.d/</code>，结果目录不存在就变成了把文件内容写进 <code>/etc/nginx/conf.d</code> 这个文件</td></tr><tr><td>目标用户是否有写权限</td><td>权限不够直接 Permission denied，中间过程白费</td></tr><tr><td>会不会静默覆盖已有文件</td><td><code>scp</code> 默认直接覆盖，没有任何提示</td></tr></tbody></table><h2 id="二、scp" tabindex="-1">二、scp <a class="header-anchor" href="#二、scp" aria-label="Permalink to &quot;二、scp&quot;">​</a></h2><p><code>scp</code> 走 SSH 加密，用法和 <code>cp</code> 很像，只是路径可以跨机器。</p><p>上传单个文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./app.conf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/etc/myapp/app.conf</span></span></code></pre></div><p>下载文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/var/log/messages</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./messages-192.168.10.129</span></span></code></pre></div><p>指定端口和私钥：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -P</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2222</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_ed25519_ops</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./app.conf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/tmp/</span></span></code></pre></div><p><code>scp</code> 的端口参数是大写 <code>-P</code>，<code>ssh</code> 是小写 <code>-p</code>。混到一起时容易敲错——<code>scp -p</code> 是保留文件属性，不是指定端口。</p><h3 id="几个常用参数" tabindex="-1">几个常用参数 <a class="header-anchor" href="#几个常用参数" aria-label="Permalink to &quot;几个常用参数&quot;">​</a></h3><p>复制整个目录：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./dist</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/opt/myapp/</span></span></code></pre></div><p><code>-r</code> 递归复制。但 <code>scp</code> 传大目录时不比较两边的差异——源端 500 个文件，目标端已经有 499 个完全一样的，<code>scp</code> 还是全部再传一遍。重复同步的场景用 <code>rsync</code> 比 <code>scp -r</code> 合理。</p><p>保留文件的时间戳和权限：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./backup.tar.gz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/backup/</span></span></code></pre></div><p>这里的 <code>-p</code>（小写）是 preserve，保留修改时间、访问时间和权限模式。</p><p>限速：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20480</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./bigfile.tar.gz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/data/</span></span></code></pre></div><p><code>-l</code> 的单位是 Kbit/s，<code>20480</code> 约等于 20 Mbit/s。跨机房传大文件或走生产网段时，不加限速可能打满链路影响线上服务。</p><p>启用 SSH 传输压缩：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./logs.tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/tmp/</span></span></code></pre></div><p><code>-C</code> 让 SSH 在传输时压缩数据。对日志、文本、配置文件有效；对已经压缩过的 <code>.tar.gz</code>、<code>.zip</code>、镜像层文件，效果不大还会白白消耗 CPU。</p><p>如果 <code>~/.ssh/config</code> 里有别名，<code>scp</code> 可以省掉很多参数：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host test-rocky</span></span>
<span class="line"><span>    HostName 192.168.10.129</span></span>
<span class="line"><span>    User root</span></span>
<span class="line"><span>    IdentityFile ~/.ssh/id_ed25519_ops</span></span>
<span class="line"><span>    IdentitiesOnly yes</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./app.conf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-rocky:/etc/myapp/</span></span></code></pre></div><h2 id="三、sftp" tabindex="-1">三、sftp <a class="header-anchor" href="#三、sftp" aria-label="Permalink to &quot;三、sftp&quot;">​</a></h2><p><code>sftp</code> 也是走 SSH，但它不一次性执行完退出，而是一个交互式客户端——连接进去后可以浏览、切换目录、上传、下载。</p><p>连接：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sftp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span></span></code></pre></div><p>进去后的常用命令：</p><table tabindex="0"><thead><tr><th>命令</th><th>作用</th><th>对应的本地操作</th></tr></thead><tbody><tr><td><code>pwd</code></td><td>显示远端当前目录</td><td></td></tr><tr><td><code>lpwd</code></td><td>显示本地当前目录</td><td></td></tr><tr><td><code>ls</code></td><td>列出远端文件</td><td><code>ssh host ls</code></td></tr><tr><td><code>lls</code></td><td>列出本地文件</td><td><code>ls</code> 本地</td></tr><tr><td><code>cd</code></td><td>切换远端目录</td><td></td></tr><tr><td><code>lcd</code></td><td>切换本地目录</td><td><code>cd</code> 本地</td></tr><tr><td><code>put</code></td><td>上传文件</td><td></td></tr><tr><td><code>get</code></td><td>下载文件</td><td></td></tr><tr><td><code>mkdir</code></td><td>创建远端目录</td><td></td></tr><tr><td><code>rm</code></td><td>删除远端文件</td><td></td></tr><tr><td><code>bye</code></td><td>退出</td><td></td></tr></tbody></table><p>一次完整会话：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sftp&gt; lpwd</span></span>
<span class="line"><span>Local working directory: /home/ops/pkg</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sftp&gt; pwd</span></span>
<span class="line"><span>Remote working directory: /root</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sftp&gt; cd /tmp</span></span>
<span class="line"><span>sftp&gt; put app.tar.gz</span></span>
<span class="line"><span>sftp&gt; get remote.log</span></span>
<span class="line"><span>sftp&gt; bye</span></span></code></pre></div><p>批处理模式用 <code>-b</code> 传入命令列表：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sftp-batch.txt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;EOF&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cd /tmp</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">put app.tar.gz</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">put app.conf</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">bye</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sftp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sftp-batch.txt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span></span></code></pre></div><p><code>sftp</code> 有断点续传命令 <code>reput</code> 和 <code>reget</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sftp&gt; reput bigfile.tar.gz        # 续传上传</span></span>
<span class="line"><span>sftp&gt; reget remote-bigfile.tar.gz # 续传下载</span></span></code></pre></div><p>但需要目标端已有部分文件且文件内容没被改过，不然续出来的文件是坏的。</p><p><code>sftp</code> 的批处理模式适合简单固定的上传下载步骤。逻辑一复杂（条件判断、错误处理、增量判断）就吃力了，这时候直接用 <code>rsync</code> 比较好。</p><h2 id="四、rsync-基础" tabindex="-1">四、rsync 基础 <a class="header-anchor" href="#四、rsync-基础" aria-label="Permalink to &quot;四、rsync 基础&quot;">​</a></h2><p><code>rsync</code> 的核心差异在增量：对比源端和目标端，只传变化的内容。文件没变就不传，文件变了只传差异部分。重复同步的场景下这个能力很重要。</p><p>安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # RHEL 系</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Debian 系</span></span></code></pre></div><p>本地同步到远端：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -av</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./dist/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/opt/myapp/dist/</span></span></code></pre></div><p>常用参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>做什么</th></tr></thead><tbody><tr><td><code>-a</code></td><td>archive 模式：递归 + 保留权限、时间戳、软链接、属主属组（权限允许时）</td></tr><tr><td><code>-v</code></td><td>显示正在传输的文件列表</td></tr><tr><td><code>-z</code></td><td>传输时压缩，适合文本类流量</td></tr><tr><td><code>-P</code></td><td>等于 <code>--partial --progress</code>：保留未传完的文件（续传） + 显示进度</td></tr><tr><td><code>--delete</code></td><td>删除目标端有但源端没有的文件</td></tr><tr><td><code>--dry-run</code></td><td>预演，打印将要发生的变化，不实际执行</td></tr></tbody></table><p>带进度和断点续传：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -avP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./large-dir/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/data/large-dir/</span></span></code></pre></div><p><code>-P</code> 里的 <code>--partial</code> 会保留已经传完的部分文件块。网络断了下次再跑可以接着传，不用从头开始。大文件跨网传输时这个能力比 <code>scp</code> 更实用。</p><p>远端拉回本地：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -avP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/var/log/nginx/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./nginx-logs/</span></span></code></pre></div><p>通过非标准端口或指定私钥：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -avP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ssh -p 2222&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./dist/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/opt/myapp/dist/</span></span></code></pre></div><p><code>-e</code> 指定底层用的远程 shell 程序。这里传的是 <code>ssh -p 2222</code>，rsync 会用这个命令来建立连接。</p><h3 id="目录末尾斜杠的差别" tabindex="-1">目录末尾斜杠的差别 <a class="header-anchor" href="#目录末尾斜杠的差别" aria-label="Permalink to &quot;目录末尾斜杠的差别&quot;">​</a></h3><p><code>rsync</code> 的源路径末尾有没有斜杠，结果完全不一样：</p><table tabindex="0"><thead><tr><th>命令</th><th>结果</th></tr></thead><tbody><tr><td><code>rsync -av ./dist/ host:/opt/app/</code></td><td>把 <code>dist</code> <strong>里面的内容</strong>同步到 <code>/opt/app/</code> 下</td></tr><tr><td><code>rsync -av ./dist host:/opt/app/</code></td><td>把 <code>dist</code> <strong>这个目录本身</strong>放到 <code>/opt/app/</code> 下，变成 <code>/opt/app/dist/</code></td></tr></tbody></table><p>不带斜杠 = 复制目录本身。带斜杠 = 复制目录里的内容。这个细节容易搞混，发布目录时先用 <code>--dry-run</code> 看一眼输出确认层级没错：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -avP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./dist/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/opt/myapp/dist/</span></span></code></pre></div><p><code>--dry-run</code> 不会实际修改目标端，只列出将要发生的变化。带 <code>--delete</code> 的同步命令尤其需要先预演——错误删除的代价远大于多花 10 秒看一眼输出。</p><h2 id="五、文件属性-权限、时间戳、属主" tabindex="-1">五、文件属性：权限、时间戳、属主 <a class="header-anchor" href="#五、文件属性-权限、时间戳、属主" aria-label="Permalink to &quot;五、文件属性：权限、时间戳、属主&quot;">​</a></h2><p>传输文件不是单纯的&quot;把数据拷过去&quot;。权限、时间戳、属主、软链接这些属性，对服务能不能正常运行有直接影响。</p><table tabindex="0"><thead><tr><th>属性</th><th>如果不正确处理</th></tr></thead><tbody><tr><td>属主/属组</td><td>服务进程可能读不了配置，或者执行不了脚本</td></tr><tr><td>权限模式</td><td><code>chmod +x</code> 脚本变成不可执行；私钥权限过宽 sshd 拒绝</td></tr><tr><td>修改时间</td><td>增量同步的比对依据，乱了以后每次都是全量</td></tr><tr><td>软链接</td><td>丢失后变成拷贝链接目标的内容，或者变成断链</td></tr></tbody></table><p>查看详细属性：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy.sh</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 比 ls -l 更细：精确时间、inode、权限八进制</span></span></code></pre></div><p><code>rsync -a</code> 尽量保留属性，但属主和属组能否保留取决于执行用户有没有权限：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -av</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./scripts/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/opt/scripts/</span></span></code></pre></div><p>如果不是 root 登录，同步过去的文件属主通常会变成登录用户自己。这不一定有问题，但要确认目标服务进程的用户确实能读写这些文件。</p><p>只想保留权限和时间戳、不改属主：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rltD</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chmod=Du=rwx,Dgo=rx,Fu=rw,Fgo=r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./dist/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app@192.168.10.129:/opt/myapp/dist/</span></span></code></pre></div><p>各参数拆开看：</p><table tabindex="0"><thead><tr><th>参数</th><th>含义</th></tr></thead><tbody><tr><td><code>-r</code></td><td>递归目录</td></tr><tr><td><code>-l</code></td><td>保留软链接（拷贝链接本身，不是链接指向的文件）</td></tr><tr><td><code>-t</code></td><td>保留文件修改时间</td></tr><tr><td><code>-D</code></td><td>保留设备文件和特殊文件</td></tr><tr><td><code>--chmod=Du=rwx,Dgo=rx,Fu=rw,Fgo=r</code></td><td>目标端强制设权限——目录所有人可读可进入，文件属主可写其他人只读</td></tr></tbody></table><p><code>--chmod</code> 的格式：<code>D</code> 代表目录，<code>F</code> 代表文件，<code>u</code>=属主，<code>g</code>=属组，<code>o</code>=其他人。Web 静态文件发布时这种显式权限声明比依赖源端权限更可靠。</p><p>另外一个常见问题：Windows 编辑的脚本传到 Linux 后，第一行的 <code>#!/bin/bash</code> 末尾带了 <code>\\r</code>（CR），执行时报 <code>/bin/bash^M: bad interpreter</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 看是不是 CRLF</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dos2unix</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy.sh</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 转换换行符</span></span></code></pre></div><h2 id="六、覆盖和删除是最危险的操作" tabindex="-1">六、覆盖和删除是最危险的操作 <a class="header-anchor" href="#六、覆盖和删除是最危险的操作" aria-label="Permalink to &quot;六、覆盖和删除是最危险的操作&quot;">​</a></h2><p><code>scp</code> 覆盖同名文件没有任何提示：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./nginx.conf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/etc/nginx/nginx.conf</span></span></code></pre></div><p>如果传错文件或者传错路径，覆盖之后想要还原就只能靠备份。所以覆盖配置前，先备份远端文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &#39;cp -a /etc/nginx/nginx.conf /etc/nginx/nginx.conf.$(date +%F-%H%M%S).bak&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./nginx.conf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/etc/nginx/nginx.conf</span></span></code></pre></div><p><code>cp -a</code> 保留原文件的权限和时间戳，回滚时和原来一致。</p><p><code>rsync --delete</code> 更危险——它不只是覆盖，还删除目标端多出来的文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -avP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./dist/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/opt/myapp/dist/</span></span></code></pre></div><p>这条命令的意思不是&quot;把源端拷过去&quot;，而是&quot;让目标端变得和源端一模一样&quot;。目标端多出来的文件会被删掉。</p><p>可以先预演：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -avP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --delete</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./dist/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/opt/myapp/dist/</span></span></code></pre></div><p>另外，路径写得越具体，误删范围越小。<code>/opt/myapp/dist/</code> 比 <code>/opt/myapp/</code> 安全得多——万一目录写错，删的是子目录，而不会把整个应用目录清掉。</p><p><code>rsync</code> 的 <code>--delete</code> 是根据源端来删除目标端。如果命令把源和目标写反了，或者源目录是空的（比如挂载失败），那目的地就可能被清空。这种事故偶尔还能见到——所以 <code>--dry-run</code> 的目的不光是确认目录层级，也是为了确认源端内容确实是你想同步的那个。</p><h2 id="七、传完之后校验" tabindex="-1">七、传完之后校验 <a class="header-anchor" href="#七、传完之后校验" aria-label="Permalink to &quot;七、传完之后校验&quot;">​</a></h2><p>关键文件传完之后做校验，确认两边是一致的。源端生成哈希：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sha256sum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.tar.gz</span></span></code></pre></div><p>远端计算：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;sha256sum /tmp/app.tar.gz&#39;</span></span></code></pre></div><p>或者把校验文件一起传过去自动比较：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sha256sum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.tar.gz</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.tar.gz.sha256</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.tar.gz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.tar.gz.sha256</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/tmp/</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    cd /tmp</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    sha256sum -c app.tar.gz.sha256</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span></code></pre></div><p><code>sha256sum -c</code> 读取校验文件，按里面的路径和哈希值比对。如果匹配，输出 <code>app.tar.gz: OK</code>；不匹配输出 <code>app.tar.gz: FAILED</code>。发布包、备份包、离线安装包，都适合加上这一步。</p><p>如果发现哈希不一致，说明文件在传输过程中损坏了——可能网络丢包、磁盘故障。TCP 有校验和但比较弱，应用层再做一次强校验（SHA-256）是对抗静默数据损坏的一个简单手段。</p><h2 id="八、通过堡垒机传文件" tabindex="-1">八、通过堡垒机传文件 <a class="header-anchor" href="#八、通过堡垒机传文件" aria-label="Permalink to &quot;八、通过堡垒机传文件&quot;">​</a></h2><p>有堡垒机之后，文件传输的方式取决于堡垒机的授权策略。常见方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>说明</th></tr></thead><tbody><tr><td>Web SFTP</td><td>在浏览器里上传下载，走堡垒机审计</td></tr><tr><td>客户端 SFTP</td><td>通过堡垒机代理连接目标资产</td></tr><tr><td>命令行 rsync/scp</td><td>需要堡垒机或 ProxyJump 允许转发</td></tr><tr><td>工单附件</td><td>先走审批，由堡垒机侧分发文件到目标机器</td></tr></tbody></table><p>如果堡垒机只允许 Web 文件管理，自己再单独开 SCP 通道直接连目标机器，等于绕过了审计。数据离开的时候没有记录，出了事反而解释不清楚，甚至被发现后本身就是一个违规操作的证据。</p><p>通过 JumpServer 这类堡垒机时，文件传输也会进审计。授权规则里要看二件事：</p><table tabindex="0"><thead><tr><th>检查</th><th>为什么</th></tr></thead><tbody><tr><td>授权是否允许文件传输</td><td>有些授权只给了&quot;连接&quot;动作，不包含&quot;文件上传/下载&quot;</td></tr><tr><td>下载是否有审计记录</td><td>带出数据的操作必须能追溯</td></tr></tbody></table><h2 id="九、lrzsz-终端里临时拖文件" tabindex="-1">九、lrzsz：终端里临时拖文件 <a class="header-anchor" href="#九、lrzsz-终端里临时拖文件" aria-label="Permalink to &quot;九、lrzsz：终端里临时拖文件&quot;">​</a></h2><p><code>lrzsz</code> 是 <code>rz</code>（接收/上传）和 <code>sz</code>（发送/下载）这一对命令，走 ZMODEM 协议，在终端里可以直接弹出文件选择对话框。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lrzsz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lrzsz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p>上传：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rz</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 客户端弹出文件选择框，选中后上传到当前目录</span></span></code></pre></div><p>下载：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/debug.log</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 客户端弹出保存路径对话框</span></span></code></pre></div><p>它能工作依赖终端客户端支持 ZMODEM。Xshell、SecureCRT、iTerm2 一般支持。很多 Web Terminal、Windows Terminal、VS Code 内置终端、浏览器终端不支持。</p><p>因为这个工具只在特定终端客户端上能用，而且操作过程不进入审计记录，所以只适合临时传一个很小的文件——比如排查问题时下载一段日志、上传一个临时用的脚本。正式发布包、备份包、大批量文件同步，还是要走 <code>rsync</code> 或堡垒机文件管理。</p><h2 id="十、常见传输问题的排查" tabindex="-1">十、常见传输问题的排查 <a class="header-anchor" href="#十、常见传输问题的排查" aria-label="Permalink to &quot;十、常见传输问题的排查&quot;">​</a></h2><h3 id="permission-denied" tabindex="-1">Permission denied <a class="header-anchor" href="#permission-denied" aria-label="Permalink to &quot;Permission denied&quot;">​</a></h3><p>出现这个提示时，先区分是哪一层的权限问题。</p><p>SSH 认证层的拒绝：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Permission denied (publickey,password).</span></span></code></pre></div><p>这是没连上——key 不对、用户不对、或者认证组合不对。</p><p>文件系统层的拒绝：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>scp: dest open &quot;/etc/myapp/app.conf&quot;: Permission denied</span></span></code></pre></div><p>这个说明已经连上服务器了，但是目标用户没有写 <code>/etc/myapp/</code> 目录的权限。可以先传到 <code>/tmp</code>，再在服务器上用 sudo 移动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./app.conf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@192.168.10.129:/tmp/app.conf</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops@192.168.10.129</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    sudo install -m 0644 -o root -g root /tmp/app.conf /etc/myapp/app.conf</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span></code></pre></div><p><code>install</code> 命令比 <code>mv</code> 更适合部署单个配置文件——它可以在移动的同时设置权限、属主、属组，一步到位。</p><h3 id="传输中断" tabindex="-1">传输中断 <a class="header-anchor" href="#传输中断" aria-label="Permalink to &quot;传输中断&quot;">​</a></h3><p><code>scp</code> 中断了只能重头传。大文件用 <code>rsync -P</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rsync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -avP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./bigfile.tar.gz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/data/</span></span></code></pre></div><p><code>-P</code> 在中断后保留了已经接收到的文件片段，重跑时会自动续传。</p><h3 id="文件名包含空格" tabindex="-1">文件名包含空格 <a class="header-anchor" href="#文件名包含空格" aria-label="Permalink to &quot;文件名包含空格&quot;">​</a></h3><p>本机路径加引号：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;./app config.conf&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129:/tmp/</span></span></code></pre></div><p>远端路径包含空格时，转义会更麻烦。服务器上文件和目录的命名最好用连字符 <code>-</code> 或下划线 <code>_</code> 替代空格，可以避免很多不必要的引号和转义问题。</p>`,145)])])}const g=a(p,[["render",d]]);export{k as __pageData,g as default};
